  function createRuntimeTerrainVisual(visual, platform) {
    if (!visual) return null;
    return clonePlain(visual);
  }

  function createMapRuntime(mapId, viewport) {
    const map = mapId && typeof mapId === 'object' ? mapId : getById(Data.MAPS, mapId) || Data.MAPS[0];
    const metrics = viewport && typeof viewport === 'object' ? viewport : createViewportMetrics();
    const authoredWorldHeight = Math.max(0, Number(map.worldHeight || 0));
    const authoredGroundY = Math.max(0, Number(map.authoredGroundY || AUTHORED_GROUND_Y));
    const geometryYOffset = authoredWorldHeight > 0 ? 0 : metrics.playfieldHeight - authoredGroundY;
    const platformDefinitions = Array.isArray(map.platforms) && map.platforms.length ? map.platforms : [[0, authoredGroundY, 2200, 80]];
    const worldWidth = Math.max(2200, ...platformDefinitions.map((platform) => platform[0] + platform[2])) + 160;
    const terrainVisuals = Array.isArray(map.terrainVisuals) ? map.terrainVisuals : [];
    const platforms = platformDefinitions.map((platform, index) => ({
      id: `${map.id}_platform_${index}`,
      index,
      x: platform[0],
      y: platform[1] + geometryYOffset,
      w: index === 0 ? Math.max(platform[2], worldWidth - platform[0]) : platform[2],
      h: index === 0 ? metrics.solidPlatformHeight : platform[3],
      dropThrough: index > 0,
      terrainVisual: terrainVisuals[index] ? createRuntimeTerrainVisual(terrainVisuals[index], platform) : null
    }));
    const lowestPlatformBottom = platforms.reduce((bottom, platform) => Math.max(bottom, Number(platform.y || 0) + Number(platform.h || 0)), 0);
    const worldHeight = Math.max(metrics.worldHeight, authoredWorldHeight, lowestPlatformBottom + metrics.solidPlatformHeight);
    const climbables = (map.climbables || []).map((climbable, index) => alignClimbable(Object.assign({}, climbable, {
      y: Number(climbable.y || 0) + geometryYOffset
    }), index, map.id, platforms));
	    const portals = distributeOverlappingPortals((map.portals || []).map((portal, index) => alignPortal(portal, index, map.id, platforms)), platforms);
    const questNpcDefinitions = (map.questNpcs || []).slice();
    if (!map.safeZone && !questNpcDefinitions.length) questNpcDefinitions.push(createMapHuntNpcDefinition(map));
    const questNpcs = questNpcDefinitions.map((npc, index) => alignQuestNpc(npc, index, map.id, platforms));
    const groundPlatform = platforms[0] || { y: metrics.playfieldHeight };
    return {
      id: map.id,
      name: map.name || '',
      asset: map.asset || '',
      palette: map.palette || [],
      environment: map.environment || null,
      townScene: map.townScene || null,
      fieldComposition: map.fieldComposition || null,
      safeZone: !!map.safeZone,
      isTrialInstance: !!map.isTrialInstance,
      trialId: normalizeId(map.trialId),
      worldWidth,
      worldHeight,
      playfieldWidth: metrics.width,
      playfieldHeight: metrics.playfieldHeight,
      solidPlatformHeight: metrics.solidPlatformHeight,
      statusHudHeight: metrics.statusHudHeight,
      hudTop: metrics.hudTop,
      platforms,
      climbables,
      portals,
      questNpcs,
      platformGraph: createPlatformGraph(platforms, climbables),
      spawnPoints: (map.spawnPoints || []).map((point, index) => {
        const platformIndex = clamp(Number(point.platformIndex || 0), 0, Math.max(0, platforms.length - 1));
        const platform = platforms[platformIndex] || platforms[0] || { x: 0, y: PLAYFIELD_HEIGHT, w: 2000, h: 80, id: `${map.id}_platform_0` };
        return {
          id: point.id || `${map.id}_spawn_${index}`,
          x: clamp(Number(point.x || platform.x + platform.w / 2), platform.x + 20, platform.x + platform.w - 20),
          y: platform.y,
          platformIndex,
          platformId: platform.id,
          weight: Math.max(1, Number(point.weight || 1))
        };
      }),
      stations: (map.stations || []).map((station) => {
        const platformIndex = clamp(Number(station.platformIndex || 0), 0, Math.max(0, platforms.length - 1));
        const stationPlatform = platforms[platformIndex] || groundPlatform;
        const x = clamp(Number(station.x || stationPlatform.x + stationPlatform.w / 2), stationPlatform.x + 12, stationPlatform.x + stationPlatform.w - 100);
        return {
          id: station.id,
          name: station.name,
          asset: station.asset || '',
          x,
          y: stationPlatform.y - 44,
          w: 88,
          h: 56,
          platformIndex,
          platformId: stationPlatform.id || ''
        };
      })
    };
  }

