      this.petRuntime = createPetRuntime();
      this.passiveRecoveryElapsed = { hp: 0, mp: 0 };
      this.passiveRecoveryCarry = { hp: 0, mp: 0 };
      this.passiveRecoveryGateReady = { hp: false, mp: false };
      this.bossIntroSummary = null;
      this.bossClearSummary = null;
      this.camera = { x: 0, y: 0 };
      this.lastFrame = 0;
      this.frameRequestId = 0;
      this.skippedFrameCount = 0;
      this.running = false;
      this.onChange = function noop() {};
      this.onToast = function noop() {};
      this.onReward = function noop() {};
      this.overlayRenderer = null;
      this.overlaySnapshotOptionsProvider = null;
      this.saveDataProvider = null;
      this.rendererBackend = null;
      this.rendererBackendPreference = 'pixi';
      this.rendererBackendStatus = 'canvas';
      this.rendererBackendInfo = { backend: 'Canvas 2D', ready: false, failed: false, active: false };
      this.rendererBackendPromise = null;
      this.loadedSaveData = null;
      this.combatMetricBuckets = [];
      this.overlaySnapshotCache = null;
      this.overlaySnapshotRevision = 0;
      this.overlaySnapshotDomainRevisions = createOverlaySnapshotDomainRevisions();
      this.cardSnapshotCache = null;
