      this.lastInteractionOpenedPanel = false;
      this.lastInteractionOpenedQuestPrompt = false;
      this.lastInteractionPanelId = '';
      this.pendingQuestNpcPrompt = null;
      this.performanceDebug = createPerformanceDebugRuntime();
